def retry_with_backoff(func, max_retries=_MAX_RETRIES, base_delay=_RETRY_BASE_DELAY):
    """Retry with exponential backoff for transient errors"""
    last_exception = None
    for attempt in range(max_retries):
        try:
            response = func()
            # Check for transient HTTP errors
            if response.status_code in (503, 429, 502, 504):
                last_exception = Exception(f"HTTP {response.status_code}")
                if attempt < max_retries - 1:
                    delay = base_delay * (2 ** attempt)
                    print(f"   ⏳ HTTP {response.status_code}, retrying in {delay}s (attempt {attempt + 2}/{max_retries})...")
                    time.sleep(delay)
                    continue
            return response
        except Exception as e:
            last_exception = e
            error_msg = str(e)
            # Only retry on transient errors
            if attempt < max_retries - 1 and any(err in error_msg.lower() for err in ['503', '429', 'timeout', 'connection', 'server_busy', 'reset']):
                delay = base_delay * (2 ** attempt)
                print(f"   ⏳ Retrying in {delay}s (attempt {attempt + 2}/{max_retries})...")
                time.sleep(delay)
            else:
                raise
    raise last_exception

